css:
@page { size: A4; margin: 0; }
body {
  margin: 0; padding: 15mm 16mm;
  background: #f5f6fb; color: #0f1222;
  font-family: 'Helvetica', 'Arial', sans-serif;
  -webkit-print-color-adjust: exact; print-color-adjust: exact;
}
.num { font-variant-numeric: tabular-nums; }
.r { text-align: right; }
.doc-header { display: block; margin: 0 0 6mm; }

.fu-top { display: flex; align-items: center; justify-content: space-between; }
.fu-brand { display: flex; align-items: center; gap: 3mm; }
.fu-mark { height: 10mm; width: 10mm; display: block; }
.fu-brandname { font-size: 12pt; font-weight: 800; letter-spacing: -0.01em; white-space: nowrap; }
.fu-doc { text-align: right; }
.fu-pill { display: inline-block; font-size: 7pt; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; color: #fff; background: linear-gradient(90deg,#7c3aed,#06b6d4); border-radius: 999px; padding: 1mm 3mm; }
.fu-docno { display: block; font-size: 11pt; font-weight: 700; margin-top: 1.4mm; }

.fu-kpis { display: flex; gap: 3mm; margin-bottom: 4mm; }
.fu-kpi { flex: 1 1 0; background: #ffffff; border: 1px solid #e7e9f2; border-radius: 3mm; padding: 4.5mm; }
.fu-kpi--hero { background: linear-gradient(135deg, #0f1222 0%, #312352 100%); border: none; color: #fff; flex: 1.3 1 0; }
.fu-kpi__k { font-size: 7pt; letter-spacing: 0.1em; text-transform: uppercase; color: #8b90a8; font-weight: 700; }
.fu-kpi--hero .fu-kpi__k { color: #b6a9e6; }
.fu-kpi__v { font-size: 22pt; font-weight: 800; letter-spacing: -0.02em; margin-top: 1.5mm; font-variant-numeric: tabular-nums; }
.fu-kpi__v2 { font-size: 12pt; font-weight: 800; margin-top: 1.5mm; }
.fu-kpi__s { font-size: 8pt; color: #8b90a8; margin-top: 1.5mm; }
.fu-kpi--hero .fu-kpi__s { color: #cfc6ee; }

.fu-ai { display: flex; align-items: center; gap: 6mm; background: linear-gradient(120deg, #7c3aed 0%, #5b3df0 45%, #06b6d4 100%); color: #fff; border-radius: 3mm; padding: 5mm 6mm; margin-bottom: 6mm; }
.fu-ai__gauge { flex: 0 0 24mm; }
.fu-gauge { width: 24mm; height: 24mm; display: block; }
.fu-ai__body { flex: 1 1 0; }
.fu-ai__hd { display: flex; align-items: center; gap: 2mm; font-size: 9pt; font-weight: 800; letter-spacing: 0.06em; text-transform: uppercase; margin-bottom: 2mm; }
.fu-spark { width: 4mm; height: 4mm; }
.fu-ai__list { margin: 0; padding-left: 4.5mm; font-size: 9.5pt; line-height: 1.55; }
.fu-ai__trend { flex: 0 0 38mm; text-align: center; }
.fu-ai__trendk { font-size: 7pt; letter-spacing: 0.08em; text-transform: uppercase; color: rgba(255,255,255,0.8); font-weight: 700; margin-bottom: 1.5mm; }
.fu-sparkline { width: 38mm; height: 13mm; display: block; }

.fu-items { width: 100%; border-collapse: collapse; margin-bottom: 6mm; }
.fu-items thead th { font-size: 7pt; letter-spacing: 0.1em; text-transform: uppercase; color: #8b90a8; font-weight: 700; text-align: left; padding: 0 2mm 2.5mm; border-bottom: 1px solid #0f1222; }
.fu-items thead th.r { text-align: right; }
.fu-items tbody td { padding: 3mm 2mm; border-bottom: 1px solid #e7e9f2; vertical-align: top; font-size: 10pt; }
.fu-items tbody td strong { font-weight: 700; }
.fu-d { display: block; color: #8b90a8; font-size: 8.5pt; margin-top: 0.6mm; }
.fu-amt { font-weight: 700; }

.fu-foot { display: flex; gap: 8mm; align-items: flex-start; }
.fu-pay { flex: 1 1 0; }
.fu-k { font-size: 7pt; letter-spacing: 0.12em; text-transform: uppercase; color: #8b90a8; font-weight: 700; }
.fu-pay__line { font-family: 'Courier New', monospace; font-size: 9.5pt; margin-top: 1.5mm; }
.fu-qr { display: flex; align-items: center; gap: 3mm; margin-top: 3.5mm; font-size: 9pt; color: #5b5f76; }
.fu-qr svg { width: 18mm; height: 18mm; }
.fu-totals { flex: 0 0 68mm; background: #fff; border: 1px solid #e7e9f2; border-radius: 3mm; padding: 5mm; }
.fu-trow { display: flex; justify-content: space-between; padding: 1.5mm 0; font-size: 10pt; color: #5b5f76; }
.fu-grand { display: flex; justify-content: space-between; margin-top: 2mm; padding-top: 3mm; border-top: 1px solid #e7e9f2; font-size: 15pt; font-weight: 800; color: #0f1222; }
.fu-grand .num { color: #7c3aed; }
.fu-ai__assist { flex: 0 0 38mm; text-align: center; background: rgba(255,255,255,0.12); border-radius: 3mm; padding: 3.5mm 3mm; }
.fu-assist__qr { display: flex; justify-content: center; }
.fu-assist__qr svg { width: 17mm; height: 17mm; background: #fff; padding: 1.4mm; border-radius: 2mm; }
.fu-assist__q { font-size: 8.5pt; font-weight: 700; margin-top: 2.2mm; }
.fu-assist__sub { font-size: 7pt; color: rgba(255,255,255,0.82); margin-top: 0.6mm; }

.fu-pagefoot { margin-top: 9mm; padding-top: 4mm; border-top: 1px solid #e7e9f2; display: flex; justify-content: space-between; gap: 6mm; font-size: 6.8pt; color: #8b90a8; }
